      {% for i in range(1, 6) %}
      <span class="text-lg {% if review.rating >= i %}text-amber-400{% else %}text-slate-200{% endif %}">★</span>
      {% endfor %}
    </div>

    <!-- Reviewer + date -->
    <div class="flex items-center gap-2 text-xs text-stone-400">
      <span class="font-medium text-stone-600">{{ review.author_name }}</span>
      <span class="px-2 py-0.5 rounded-full text-xs font-medium capitalize {{ role_styles.get(review.reviewer_role, 'bg-stone-100 text-stone-500') }}">
        {{ review.reviewer_role | title }}
      </span>
      <span>{{ review.created_at }}</span>
    </div>
  </div>

  <!-- Tags -->
  {% if review.tags %}
  <div class="flex flex-wrap gap-1.5">
    {% for tag in review.tags %}
    <span class="text-xs px-2 py-0.5 rounded-full bg-teal-50 text-teal-700 border border-teal-100">{{ tag }}</span>
    {% endfor %}
  </div>
  {% endif %}

  <!-- Review text -->
  {% if review.text %}
  <p class="text-sm text-stone-700 leading-relaxed">{{ review.text }}</p>
  {% endif %}

  <!-- Image thumbnails -->
  {% if review.images %}
  <div class="flex flex-wrap gap-2 mt-1">
    {% for img in review.images %}
    <img src="{{ img.file_path }}" alt="Review photo"
         class="w-20 h-20 object-cover rounded-xl border border-stone-200" />
    {% endfor %}
  </div>
  {% endif %}

