    <!-- Edit (opens inline edit form) -->
    <button
      hx-get="{{ url_for('reviews.review_form', reservation_id=review.reservation_id) }}"
      class="text-xs font-medium text-stone-500 hover:text-brand-700 border border-stone-200 hover:border-brand-300 px-2.5 py-1 rounded-lg transition-colors">
      Edit
    </button>
    <!-- Delete -->
    <button
      hx-delete="{{ url_for('reviews.delete_review', review_id=review.id) }}"
      hx-target="#review-card-{{ review.id }}"
      hx-swap="outerHTML"
      hx-confirm="Delete this review? This cannot be undone."
      class="text-xs font-medium text-red-500 hover:text-red-700 border border-transparent hover:border-red-200 hover:bg-red-50 px-2.5 py-1 rounded-lg transition-colors">
      Delete
    </button>

    {% else %}
    <!-- Dispute -->
    {% if review.status == 'active' %}
    <button
      hx-get="{{ url_for('reviews.session_reviews', session_id=session_id if session_id is defined else 0) }}#appeal-{{ review.id }}"
      onclick="document.getElementById('appeal-form-{{ review.id }}').classList.toggle('hidden')"
      class="text-xs font-medium text-amber-600 hover:text-amber-800 border border-amber-200 hover:bg-amber-50 px-2.5 py-1 rounded-lg transition-colors">
      Dispute
    </button>

    <!-- Inline appeal form -->
    <div id="appeal-form-{{ review.id }}" class="hidden w-full mt-2">
      {% set review_id_val = review.id %}
      {% include "partials/reviews/appeal_form.html" %}
    </div>
    {% endif %}

    {% if review.status == 'disputed' %}
    <span class="text-xs text-amber-600 font-medium px-2 py-1">Under dispute</span>
    {% endif %}

    {% endif %}

  </div>
  {% endif %}

  {% if review.status == 'removed' %}
  <p class="text-xs text-red-400 italic">This review has been removed.</p>
  {% endif %}

</div>
"}

