                  <input type="hidden" name="csrf_token" value="{{ csrf_token() }}" />
                  <button type="submit"
                    class="w-full text-left px-4 py-2 text-sm text-red-600 hover:bg-red-50 transition-colors">
                    Log out
                  </button>
                </form>
              </div>
            </div>
          </div>

          <!-- Mobile hamburger -->
          <button
            type="button"
            id="mobile-menu-btn"
            aria-label="Open navigation"
            onclick="document.getElementById('mobile-menu').classList.toggle('hidden')"
            class="md:hidden inline-flex items-center justify-center p-2 rounded-md text-stone-500 hover:text-brand-700 hover:bg-stone-100 transition-colors focus:outline-none">
            <svg class="w-5 h-5" fill="none" stroke="currentColor" stroke-width="2" viewBox="0 0 24 24">
              <path stroke-linecap="round" stroke-linejoin="round" d="M4 6h16M4 12h16M4 18h16" />
            </svg>
          </button>

        </div><!-- /right -->

        {% else %}
        <!-- Unauthenticated -->
        <div class="flex items-center gap-4">
          <a href="{{ url_for('auth.login') }}"
             class="text-sm font-medium text-stone-600 hover:text-brand-700">Log in</a>
          <a href="{{ url_for('auth.register') }}"
             class="text-sm font-medium bg-brand-600 text-white px-4 py-2 rounded-lg hover:bg-brand-700 transition-colors">
            Sign up
          </a>
        </div>
        {% endif %}

      </div>
    </div>

    <!-- ── Mobile menu ──────────────────────────────────────────── -->
    {% if current_user.is_authenticated %}
    <div id="mobile-menu" class="hidden md:hidden border-t border-stone-100 bg-white px-4 pb-3 pt-2 space-y-1">
      <a href="{{ url_for('booking.schedule') }}" class="mobile-nav-link">Schedule</a>
      <a href="{{ url_for('booking.my_bookings') }}" class="mobile-nav-link">My Bookings</a>
      <a href="{{ url_for('reviews.index') }}" class="mobile-nav-link">Reviews</a>
      {% if current_user.role in ['staff', 'admin'] %}
      <a href="{{ url_for('staff.index') }}" class="mobile-nav-link">Staff</a>
      <a href="{{ url_for('analytics.index') }}" class="mobile-nav-link">Analytics</a>
      {% endif %}
      {% if current_user.role in ['editor', 'admin'] %}
      <a href="{{ url_for('content.browse') }}" class="mobile-nav-link">Content</a>
      {% endif %}
      {% if current_user.role == 'admin' %}
      <a href="{{ url_for('admin.index') }}" class="mobile-nav-link">Admin</a>
      {% endif %}
      <div class="border-t border-stone-100 pt-2 mt-2">
        <p class="text-xs text-stone-400 px-3 mb-1">{{ current_user.username }} · {{ current_user.role }}</p>
        <form action="{{ url_for('auth.logout') }}" method="post">
          <input type="hidden" name="csrf_token" value="{{ csrf_token() }}" />
          <button type="submit" class="w-full text-left px-3 py-2 text-sm text-red-600 hover:bg-red-50 rounded-lg transition-colors">
            Log out
          </button>
        </form>
      </div>
    </div>
    {% endif %}

  </nav>

  <!-- Close desktop dropdown on outside click -->
  <script>
    document.addEventListener('click', function(e) {
      const wrapper = document.getElementById('user-menu-wrapper');
      const dropdown = document.getElementById('user-dropdown');
      if (wrapper && dropdown && !wrapper.contains(e.target)) {
        dropdown.classList.add('hidden');
      }
    });
  </script>

  <!-- ── Global HTMX loading bar ─────────────────────────────────── -->
  <div id="htmx-progress"
       class="fixed top-0 left-0 h-0.5 bg-brand-500 z-50 transition-all duration-300"
       style="width:0;opacity:0"></div>
  <script>
    (function () {
      var bar = document.getElementById('htmx-progress');
      document.body.addEventListener('htmx:beforeRequest', function () {
        bar.style.width = '0'; bar.style.opacity = '1';
        bar.style.width = '40%';
      });
      document.body.addEventListener('htmx:afterRequest', function () {
        bar.style.width = '100%';
        setTimeout(function () { bar.style.opacity = '0'; bar.style.width = '0'; }, 300);
      });
    })();
  </script>

  <!-- ── Flash messages ──────────────────────────────────────────── -->
  <div id="flash-container" class="max-w-7xl mx-auto w-full px-4 sm:px-6 lg:px-8 pt-4">
    {% with messages = get_flashed_messages(with_categories=true) %}
      {% if messages %}
        {% for category, message in messages %}
          {% include "partials/flash.html" %}
        {% endfor %}
      {% endif %}
    {% endwith %}
  </div>

  <!-- ── Main content ────────────────────────────────────────────── -->
  <main class="flex-1 max-w-7xl mx-auto w-full px-4 sm:px-6 lg:px-8 py-8">
    {% block content %}{% endblock %}
  </main>

  <footer class="border-t border-stone-200 mt-auto py-6 text-center text-xs text-stone-400">
    &copy; {{ now().year }} StudioOps. All rights reserved.
  </footer>

  <!-- ── Tailwind utility classes for nav (applied via @layer in CSS) ── -->
  <style>
    .nav-link {
      @apply text-sm font-medium text-stone-600 hover:text-brand-700 px-3 py-1.5 rounded-lg hover:bg-brand-50 transition-colors;
    }
    .nav-link-active {
      @apply text-brand-700 bg-brand-50;
    }
    .mobile-nav-link {
      @apply block px-3 py-2 text-sm font-medium text-stone-600 hover:text-brand-700 hover:bg-stone-50 rounded-lg transition-colors;
    }
  </style>

  <!-- ── Client-side error logging ──────────────────────────────── -->
  <script>
  (function () {
    var _endpoint = '/analytics/client-error';

    function _send(message, stack) {
      try {
        var body = 'message=' + encodeURIComponent((message || '').slice(0, 500))
                 + '&stack='   + encodeURIComponent((stack   || '').slice(0, 1000))
                 + '&page='    + encodeURIComponent(window.location.pathname);
        var xhr = new XMLHttpRequest();
        xhr.open('POST', _endpoint, true);
        xhr.setRequestHeader('Content-Type', 'application/x-www-form-urlencoded');
        xhr.send(body);
      } catch (e) { /* never let logging itself crash the page */ }
    }

    window.addEventListener('error', function (e) {
      _send(e.message, e.error && e.error.stack ? e.error.stack : '');
    });
    window.addEventListener('unhandledrejection', function (e) {
      var reason = e.reason;
      var msg = reason instanceof Error ? reason.message : String(reason);
      var stack = reason instanceof Error ? (reason.stack || '') : '';
      _send('Unhandled rejection: ' + msg, stack);
    });
    document.addEventListener('htmx:responseError', function (e) {
      _send('HTMX error: ' + e.detail.xhr.status + ' on ' + (e.detail.pathInfo && e.detail.pathInfo.requestPath || 'unknown'), '');
    });
  })();
  </script>

</body>
</html>
"}

